/* Compara productos críticos con notificaciones sin leer para evitar duplicados.
   Entrada: items[0].json -> array de productos críticos
           items[1].json -> array de notificaciones sin leer (cada notificación puede contener campo .productos con array)
   Salida: { "duplicado": true/false }
*/
const productosCriticos = $input.item.json || [];
const notifs = $input.all()[1] ? $input.all()[1].json : [];

// Obtener IDs de productos críticos
const idsCriticos = (Array.isArray(productosCriticos) ? productosCriticos : []).map(p => p._id);

let duplicado = false;

if (Array.isArray(notifs)) {
  for (const n of notifs) {
    const prod = n.productos || n.body || n.productos || [];
    const prodIds = Array.isArray(prod) ? prod.map(p => p._id) : [];
    // Si hay intersección completa (todos los IDs críticos están contenidos en la notificación sin leer), consideramos duplicado
    if (idsCriticos.length > 0 && idsCriticos.every(id => prodIds.includes(id))) {
      duplicado = true;
      break;
    }
  }
}

return [{ json: { duplicado, productosCriticos, notifs } }];

/* Genera el RESUMEN DE EJECUCIÓN final según especificación */
const fecha = $now.format('DD/MM/YYYY HH:mm','America/Guayaquil');
const productosRevisados = Array.isArray($json.productosRevisados) ? $json.productosRevisados.length : ($json.productosCriticos ? $json.productosCriticos.length : 0);
const productosCriticos = $json.productosCriticos ? $json.productosCriticos.length : 0;
const notificacionEnviada = $json.notificacionId ? 'Sí' : 'No';
const aprobacion = $json.aprobacion === 'aprobado' ? 'Aprobado' : ($json.aprobacion === 'rechazado' ? 'Rechazado' : 'Pendiente');
const emailEnviado = $json.emailEnviado ? 'Enviado' : 'No enviado';
const estadoFinal = $json.estadoFinal || (aprobacion === 'Aprobado' && emailEnviado === 'Enviado' ? 'Completado' : 'Cancelado');

const resumen = `RESUMEN DE EJECUCIÓN — ${fecha}\n─────────────────────────────────────\nProductos revisados: ${productosRevisados}\nProductos críticos encontrados: ${productosCriticos}\nNotificación enviada al admin: ${notificacionEnviada}\nAprobación del admin: ${aprobacion}\nEmail al proveedor: ${emailEnviado}\nEstado final: ${estadoFinal}\n─────────────────────────────────────`;

return [{ json: { resumen, fecha, productosRevisados, productosCriticos, notificacionEnviada, aprobacion, emailEnviado, estadoFinal } }];

/* Manejo de error 401 o 500 en la respuesta de 'Consultar stock crítico'.
   Si code === 401 -> Detener y registrar error.
   Si code === 500 -> reenviar (nota: n8n puede reintentar o usar un Delay para reintento manual).
*/
const resp = $input.item.json;
if (resp && resp.statusCode === 401) {
  return [{ json: { error: '401', mensaje: 'Credenciales incorrectas. Deteniendo ejecución.' } }];
}
if (resp && resp.statusCode === 500) {
  return [{ json: { error: '500', mensaje: 'Error 500 — reintentar tras 5 minutos.' } }];
}
return [{ json: { ok: true } }];
